import { defineStore } from 'pinia'
import { ref } from 'vue'

const STORAGE_KEY = 'Comfy.NodeTypeColorDefaults.v1'

export interface NodeTypeColorPair {
  color: string
  bgcolor: string
}

/**
 * Persisted default colors per Comfy node.type + UI flag for the palette dialog.
 */
export const useNodeTypeColorStore = defineStore('nodeTypeColorDefaults', () => {
  const paletteOpen = ref(false)
  const typeColors = ref<Record<string, NodeTypeColorPair>>({})

  function loadFromStorage() {
    try {
      const raw = localStorage.getItem(STORAGE_KEY)
      if (raw) typeColors.value = JSON.parse(raw) as Record<string, NodeTypeColorPair>
    } catch {
      /* ignore */
    }
  }

  function persist() {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(typeColors.value))
    } catch {
      /* ignore */
    }
  }

  loadFromStorage()

  function openPalette() {
    paletteOpen.value = true
  }

  function closePalette() {
    paletteOpen.value = false
  }

  function togglePalette() {
    paletteOpen.value = !paletteOpen.value
  }

  function setTypeDefault(nodeType: string, pair: NodeTypeColorPair) {
    typeColors.value = { ...typeColors.value, [nodeType]: { ...pair } }
    persist()
  }

  function clearTypeDefault(nodeType: string) {
    if (!(nodeType in typeColors.value)) return
    const next = { ...typeColors.value }
    delete next[nodeType]
    typeColors.value = next
    persist()
  }

  function clearAllTypeDefaults() {
    if (!Object.keys(typeColors.value).length) return
    typeColors.value = {}
    persist()
  }

  function getTypeDefault(nodeType: string): NodeTypeColorPair | undefined {
    return typeColors.value[nodeType]
  }

  return {
    paletteOpen,
    typeColors,
    openPalette,
    closePalette,
    togglePalette,
    setTypeDefault,
    clearTypeDefault,
    clearAllTypeDefaults,
    getTypeDefault,
    loadFromStorage
  }
})
