import type { LGraph } from '@/lib/litegraph/src/LGraph'
import type { LGraphNode } from '@/lib/litegraph/src/litegraph'
import { forEachNode } from '@/utils/graphTraversalUtil'
import { adjustColor } from '@/utils/colorUtil'

/**
 * Apply header/body colors and notify Vue node layer (property triggers).
 */
export function applyNodeColorPair(
  node: LGraphNode,
  color: string | undefined,
  bgcolor: string | undefined
): void {
  const g = node.graph
  if (!g) return
  const oldC = node.color
  const oldBg = node.bgcolor
  if (oldC === color && oldBg === bgcolor) return

  g.beforeChange(node)
  node.color = color
  node.bgcolor = bgcolor
  g.afterChange()

  if (oldC !== color) {
    g.trigger('node:property:changed', {
      nodeId: node.id,
      property: 'color',
      oldValue: oldC,
      newValue: color
    })
  }
  if (oldBg !== bgcolor) {
    g.trigger('node:property:changed', {
      nodeId: node.id,
      property: 'bgcolor',
      oldValue: oldBg,
      newValue: bgcolor
    })
  }
}

/** Derive Comfy-style header/body pair from one accent (Houdini-like pick). */
export function pairFromAccentHex(hex: string): { color: string; bgcolor: string } {
  const h = hex.startsWith('#') ? hex : `#${hex}`
  return {
    color: adjustColor(h, { lightness: -0.06 }),
    bgcolor: adjustColor(h, { lightness: 0.1 })
  }
}

/**
 * Remove custom color/bgcolor/boxcolor so the node uses class/theme defaults again.
 */
export function clearNodeColorOverrides(node: LGraphNode): void {
  const g = node.graph
  if (!g) return
  if (node.boxcolor !== undefined) {
    g.beforeChange(node)
    node.boxcolor = undefined
    g.afterChange()
  }
  applyNodeColorPair(node, undefined, undefined)
}

/**
 * Clear custom node colors everywhere under the root graph (including nested subgraphs).
 */
export function clearAllNodeColorOverridesInHierarchy(
  rootGraph: LGraph | undefined
): void {
  if (!rootGraph) return
  forEachNode(rootGraph, (node) => {
    clearNodeColorOverrides(node)
  })
}
